534	// UsageData holds structured token usage from a structured agent output.
535	type UsageData struct {
536		InputTokens  int
537		OutputTokens int
538		CostUSD      float64
539	}
540	
541	// ExtractUsage parses structured token usage from agent output.
542	// For codex, it scans JSONL output for a turn.completed event and reads the usage object.
543	// For claude, it parses the --output-format json envelope (whole output or last non-empty line).
544	// Returns zero-value UsageData if parsing fails or the harness is unsupported.
545	func ExtractUsage(harnessName string, output string) UsageData {
546		switch harnessName {
547		case "codex":
548			for _, line := range strings.Split(output, "\n") {
549				line = strings.TrimSpace(line)
550				if line == "" || !strings.Contains(line, `"turn.completed"`) {
551					continue
552				}
553				var event struct {
554					Type  string `json:"type"`
555					Usage struct {
556						InputTokens  int `json:"input_tokens"`
557						OutputTokens int `json:"output_tokens"`
558					} `json:"usage"`
559				}
560				if err := json.Unmarshal([]byte(line), &event); err != nil {
561					continue
562				}
563				if event.Type == "turn.completed" {
564					return UsageData{
565						InputTokens:  event.Usage.InputTokens,
566						OutputTokens: event.Usage.OutputTokens,
567					}
568				}
569			}
570			return UsageData{}
571		case "claude":
572			// Claude may emit either the legacy single-JSON envelope
573			// ({"usage":{...},"total_cost_usd":N,"result":"..."}) or a stream-json
574			// sequence of one JSON event per line, the last of which is a
575			// {"type":"result",...} event with the same usage/cost fields.
576			return extractUsageClaude(output)
577		case "opencode":
578			// opencode -f json emits a JSON object; parse usage fields if present.
579			var envelope struct {
580				Usage struct {
581					InputTokens  int `json:"input_tokens"`
582					OutputTokens int `json:"output_tokens"`
583				} `json:"usage"`
584				TotalCostUSD float64 `json:"total_cost_usd"`
585			}
586			if err := json.Unmarshal([]byte(output), &envelope); err != nil {
587				// Try last non-empty line (in case of preamble).
588				lines := strings.Split(strings.TrimRight(output, "\n"), "\n")
589				last := ""
590				for i := len(lines) - 1; i >= 0; i-- {
591					if strings.TrimSpace(lines[i]) != "" {
592						last = lines[i]
593						break
594					}
595				}
596				if last == "" {
597					return UsageData{}
598				}
599				if err2 := json.Unmarshal([]byte(last), &envelope); err2 != nil {
600					return UsageData{}
601				}
602			}
603			if envelope.Usage.InputTokens == 0 && envelope.Usage.OutputTokens == 0 && envelope.TotalCostUSD == 0 {
604				return UsageData{}
605			}
606			return UsageData{
607				InputTokens:  envelope.Usage.InputTokens,
608				OutputTokens: envelope.Usage.OutputTokens,
609				CostUSD:      envelope.TotalCostUSD,
610			}
611		case "pi":
612			// pi outputs JSONL - cost is in intermediate events, summary at end has no cost
613			// Scan backwards to find the last line with cost data
614			lines := strings.Split(strings.TrimRight(output, "\n"), "\n")
615			var inputTokens, outputTokens int
616			var costUSD float64
617			for i := len(lines) - 1; i >= 0; i-- {
618				line := strings.TrimSpace(lines[i])
619				if line == "" {
620					continue
621				}
622				// Try to parse as pi event with usage/cost
623				// Format: {"type":"text_end","message":{"usage":{"input":N,"output":M,"cost":{"total":X}}}}
624				var event struct {
625					Type    string `json:"type"`
626					Message struct {
627						Usage struct {
628							Input  int `json:"input"`
629							Output int `json:"output"`
630							Cost   struct {
631								Total float64 `json:"total"`
632							} `json:"cost"`
633						} `json:"usage"`
634					} `json:"message"`
635					Partial struct {
636						Usage struct {
637							Input  int `json:"input"`
638							Output int `json:"output"`
639							Cost   struct {
640								Total float64 `json:"total"`
641							} `json:"cost"`
642						} `json:"usage"`
643					} `json:"partial"`
644				}
645				if err := json.Unmarshal([]byte(line), &event); err != nil {
646					continue
647				}
648				// Check message.usage first, then partial.usage
649				if event.Message.Usage.Input > 0 || event.Message.Usage.Output > 0 {
650					inputTokens = event.Message.Usage.Input
651					outputTokens = event.Message.Usage.Output
652					costUSD = event.Message.Usage.Cost.Total
653					break
654				}
655				if event.Partial.Usage.Input > 0 || event.Partial.Usage.Output > 0 {
656					inputTokens = event.Partial.Usage.Input
657					outputTokens = event.Partial.Usage.Output
658					costUSD = event.Partial.Usage.Cost.Total
659					break
660				}
661			}
662			return UsageData{
663				InputTokens:  inputTokens,
664				OutputTokens: outputTokens,
665				CostUSD:      costUSD,
666			}
667		case "gemini":
668			// gemini outputs single JSON with stats.models[].tokens (no cost in JSON)
669			lines := strings.Split(strings.TrimRight(output, "\n"), "\n")
670			last := ""
671			for i := len(lines) - 1; i >= 0; i-- {
672				if strings.TrimSpace(lines[i]) != "" {
673					last = lines[i]
674					break
675				}
676			}
677			if last == "" {
678				return UsageData{}
679			}
680			var envelope struct {
681				Stats struct {
682					Models map[string]struct {
683						Tokens struct {
684							Input int `json:"input"`
685							Total int `json:"total"`
686						} `json:"tokens"`
687					} `json:"models"`
688				} `json:"stats"`
689			}
690			if err := json.Unmarshal([]byte(last), &envelope); err != nil {
691				return UsageData{}
692			}
693			inputTokens := 0
694			outputTokens := 0
695			for _, model := range envelope.Stats.Models {
696				inputTokens += model.Tokens.Input
697				outputTokens += model.Tokens.Total - model.Tokens.Input
698			}
699			// Gemini JSON output doesn't include cost
700			return UsageData{
701				InputTokens:  inputTokens,
702				OutputTokens: outputTokens,
703				CostUSD:      0,
704			}
705		default:
706			return UsageData{}
707		}
708	}
