710	// ExtractOutput extracts clean text from raw agent output based on harness format.
711	// For codex: scans JSONL for type=item.completed with item.type=agent_message, returns item.text
712	// For claude: parses JSON envelope and returns the 'result' field
713	// For agent/opencode: returns output as-is (no transformation needed)
714	// For unknown harnesses or malformed input: returns output as-is
715	func ExtractOutput(harnessName string, rawOutput string) string {
716		switch harnessName {
717		case "codex":
718			return extractOutputCodex(rawOutput)
719		case "claude":
720			return extractOutputClaude(rawOutput)
721		case "agent", "opencode":
722			// agent and opencode return clean text directly
723			return rawOutput
724		case "pi", "gemini":
725			return extractOutputPiGemini(rawOutput)
726		default:
727			// Unknown harnesses return output as-is
728			return rawOutput
729		}
730	}
731	
732	func extractOutputPiGemini(rawOutput string) string {
733		// pi outputs JSONL (last line has summary), gemini outputs single JSON
734		// Try to parse the last non-empty line for the response field
735		lines := strings.Split(strings.TrimRight(rawOutput, "\n"), "\n")
736		last := ""
737		for i := len(lines) - 1; i >= 0; i-- {
738			if strings.TrimSpace(lines[i]) != "" {
739				last = lines[i]
740				break
741			}
742		}
743		if last == "" {
744			return rawOutput
745		}
746		var envelope struct {
747			Response string `json:"response"`
748		}
749		if err := json.Unmarshal([]byte(last), &envelope); err != nil {
750			return rawOutput
751		}
752		return envelope.Response
753	}
754	
755	func extractOutputCodex(rawOutput string) string {
756		for _, line := range strings.Split(rawOutput, "\n") {
757			line = strings.TrimSpace(line)
758			if line == "" {
759				continue
760			}
761			var item struct {
762				Type string `json:"type"`
763				Item struct {
764					Type string `json:"type"`
765					Text string `json:"text"`
766				} `json:"item"`
767			}
768			if err := json.Unmarshal([]byte(line), &item); err != nil {
769				continue
770			}
771			if item.Type == "output" && item.Item.Type == "agent_message" {
772				return item.Item.Text
773			}
774		}
775		return rawOutput
776	}
