810	// extractUsageClaude parses token usage and cost from claude output.
811	// It handles both the legacy non-streaming envelope and the stream-json
812	// format (one JSON event per line, final "result" event carries usage).
813	func extractUsageClaude(output string) UsageData {
814		parse := func(s string) (UsageData, bool) {
815			var envelope struct {
816				Type  string `json:"type"`
817				Usage struct {
818					InputTokens  int `json:"input_tokens"`
819					OutputTokens int `json:"output_tokens"`
820				} `json:"usage"`
821				TotalCostUSD float64 `json:"total_cost_usd"`
822			}
823			if err := json.Unmarshal([]byte(s), &envelope); err != nil {
824				return UsageData{}, false
825			}
826			if envelope.Usage.InputTokens == 0 && envelope.Usage.OutputTokens == 0 && envelope.TotalCostUSD == 0 {
827				return UsageData{}, false
828			}
829			return UsageData{
830				InputTokens:  envelope.Usage.InputTokens,
831				OutputTokens: envelope.Usage.OutputTokens,
832				CostUSD:      envelope.TotalCostUSD,
833			}, true
834		}
835	
836		// Try whole output as a single JSON envelope first (legacy path).
837		if u, ok := parse(output); ok {
838			return u
839		}
840		// Stream-json: scan lines, prefer the final "type":"result" event,
841		// else fall back to the last line that parses with usage.
842		lines := strings.Split(strings.TrimRight(output, "\n"), "\n")
843		for i := len(lines) - 1; i >= 0; i-- {
844			line := strings.TrimSpace(lines[i])
845			if line == "" {
846				continue
847			}
848			if u, ok := parse(line); ok {
849				return u
850			}
851		}
852		return UsageData{}
853	}
