855	// ExtractTokens parses token usage from agent output using the harness's pattern.
856	// For codex, it delegates to ExtractUsage and returns total tokens (input + output).
857	func ExtractTokens(output string, harness harnessConfig) int {
858		if harness.Name == "codex" {
859			usage := ExtractUsage("codex", output)
860			if usage.InputTokens > 0 || usage.OutputTokens > 0 {
861				return usage.InputTokens + usage.OutputTokens
862			}
863		}
864		if harness.TokenPattern == "" {
865			return 0
866		}
867		re, err := regexp.Compile(harness.TokenPattern)
868		if err != nil {
869			return 0
870		}
871		matches := re.FindStringSubmatch(output)
872		if len(matches) > 1 {
873			cleaned := strings.ReplaceAll(matches[1], ",", "")
874			n, _ := strconv.Atoi(cleaned)
875			return n
876		}
877		return 0
878	}
